// sensor_module.h — 对外的抽象接口
#ifndef SENSOR_MODULE_H
#define SENSOR_MODULE_H

typedef struct sensor_handle sensor_handle_t;

typedef struct {
    float temperature;   // °C
    float humidity;      // %RH
    uint32_t timestamp;  // ms since boot
} sensor_reading_t;

// 初始化：内部用全局 I2C 实例，对外不暴露
sensor_handle_t* sensor_init(uint8_t i2c_addr);

// 读取：原子性获取一组相关读数
int sensor_read(sensor_handle_t* h, sensor_reading_t* out);

// 销毁
void sensor_destroy(sensor_handle_t* h);

#endif

// sensor_module.c — 模块内部实现（对用户不可见）
#include "sensor_module.h"
#include <string.h>

// 完整结构体：只在 .c 文件中定义
struct sensor_handle {
    uint8_t i2c_addr;          // 设备地址
    I2C_HandleTypeDef* hi2c;   // HAL I2C 句柄
    uint32_t last_read_tick;   // 上次读取时间戳
    sensor_reading_t cached;   // 缓存的读数
    uint8_t init_flag;         // 初始化标记
};

// 内部：读取单个寄存器
static int16_t read_register(sensor_handle_t* h, uint8_t reg) {
    uint8_t buf[2];
    if (HAL_I2C_Mem_Read(h->hi2c, h->i2c_addr, reg, 1, buf, 2, 100)
        != HAL_OK) {
        return -1;
    }
    return (int16_t)((buf[0] << 8) | buf[1]);
}

sensor_handle_t* sensor_init(uint8_t i2c_addr) {
    sensor_handle_t* h = calloc(1, sizeof(*h));
    if (!h) return NULL;
    h->i2c_addr = i2c_addr;
    h->init_flag = 1;
    return h;
}

int sensor_read(sensor_handle_t* h, sensor_reading_t* out) {
    if (!h || !out || !h->init_flag) return -1;

    int16_t raw_temp = read_register(h, 0x07);  // TEMP_OUT
    int16_t raw_humi = read_register(h, 0x08);  // HUMIDITY_OUT
    if (raw_temp < 0 || raw_humi < 0) return -1;

    // 转换：假设传感器精度为 0.01
    out->temperature = raw_temp / 100.0f;
    out->humidity = raw_humi / 100.0f;
    out->timestamp = xTaskGetTickCount();

    h->cached = *out;
    h->last_read_tick = out->timestamp;
    return 0;
}

