// ✅ 正确做法：通过句柄 + 临界区
static float g_motor_speed;  // static：仅限本文件

void HAL_TIM_PeriodElapsedCallback(TIM_HandleTypeDef* h) {
    if (h->Instance == TIM2) {
        uint32_t ms = OS_GetTickCount();
        portENTER_CRITICAL();
        g_motor_speed = read_encoder();
        g_last_update_ms = ms;
        portEXIT_CRITICAL();
    }
}

void PID_Task(void const* argument) {
    for (;;) {
        float speed;
        portENTER_CRITICAL();
        speed = g_motor_speed;
        portEXIT_CRITICAL();
        float output = pid_update(&pid_ctx, SETPOINT - speed);
        set_pwm(output);
        osDelay(10);
    }
}

