// motor.h — 不变
typedef struct { int speed; int direction; } motor_config_t;
void motor_init(const motor_config_t* cfg);
void motor_set_speed(int speed);
int  motor_get_speed(void);

// motor.c — 改动
static motor_config_t g_cfg;       // extern → static
static volatile int   g_speed;     // extern → static + volatile

void motor_set_speed(int speed) {  // 新增校验
    if (speed < -100 || speed > 100) return;
    g_speed = speed;
    __HAL_TIM_SET_COMPARE(&htim1, TIM_CHANNEL_1, speed + 100);
}

int motor_get_speed(void) {      // 新增临界区
    int s;
    __disable_irq();
    s = g_speed;
    __enable_irq();
    return s;
}

